"use client";

import React, { useEffect, useRef } from "react";

// Global variable to keep the source canvas cached so we don't regenerate the halftone art every time
let globalSourceCanvas: HTMLCanvasElement | null = null;

export default function HalftoneArt() {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    if (globalSourceCanvas) {
      const canvas = canvasRef.current;
      const ctx = canvas?.getContext("2d");
      if (ctx && canvas) {
        ctx.drawImage(globalSourceCanvas, 0, 0);
      }
      return;
    }

    const img = new window.Image();
    img.onload = () => {
      const grid = 46;
      const off = document.createElement("canvas");
      off.width = grid;
      off.height = grid;
      const octx = off.getContext("2d");
      if (!octx) return;
      octx.imageSmoothingEnabled = true;

      const scale = Math.min(grid / img.width, grid / img.height);
      const w = img.width * scale,
        h = img.height * scale;
      octx.fillStyle = "#ffffff";
      octx.fillRect(0, 0, grid, grid);
      octx.drawImage(img, (grid - w) / 2, (grid - h) / 2, w, h);

      const data = octx.getImageData(0, 0, grid, grid).data;

      const canvas = canvasRef.current;
      if (!canvas) return;
      const size = canvas.width;
      const cell = size / grid;
      const ctx = canvas.getContext("2d");
      if (!ctx) return;
      ctx.clearRect(0, 0, size, size);

      for (let y = 0; y < grid; y++) {
        for (let x = 0; x < grid; x++) {
          const i = (y * grid + x) * 4;
          const r = data[i],
            g = data[i + 1],
            b = data[i + 2],
            a = data[i + 3] / 255;
          const lum = (0.299 * r + 0.587 * g + 0.114 * b) / 255;
          const ink = (1 - lum) * a;
          if (ink > 0.06) {
            const radius = (cell / 2) * Math.min(1, ink * 1.15);
            ctx.beginPath();
            ctx.fillStyle =
              "rgba(215,222,230," + Math.min(1, 0.55 + ink * 0.5) + ")";
            ctx.arc(
              x * cell + cell / 2,
              y * cell + cell / 2,
              radius,
              0,
              Math.PI * 2
            );
            ctx.fill();
          }
        }
      }
      
      globalSourceCanvas = document.createElement("canvas");
      globalSourceCanvas.width = canvas.width;
      globalSourceCanvas.height = canvas.height;
      globalSourceCanvas.getContext("2d")?.drawImage(canvas, 0, 0);

    };
    img.src = "data:image/png;base64,";
  }, []);

  return <canvas ref={canvasRef} width="220" height="220" className="block max-sm:w-[120px] max-sm:h-[120px]"></canvas>;
}
